class Node:
    def __init__(self, char):
        self.char = char
        self.left = None
        self.right = None

def insert_into_bst(node, char):
    if node is None:
        return Node(char)
    if char < node.char:
        node.left = insert_into_bst(node.left, char)
    else:
        node.right = insert_into_bst(node.right, char)
    return node

def process_sequence(sequence):
    root = None
    for char in sequence:
        root = insert_into_bst(root, char.lower())
    return root

